"""
MKT Original Commentary — Mark chapters 10–11
Run: python3 scripts/zc-original-mark-10-11.py

Source data used:
- data/interlinear/mark.json
- data/translation/draft/mediating/mark.json
- data/commentary/mkt-original/mark.json (existing entries skipped by merge_comm)

Key decisions in this range:
- 10:5 sklērokardia: "hardness of heart" — divorce permitted as concession, not creation-ideal
- 10:6 ap' archēs ktiseōs: "from the beginning of creation" — Jesus grounds the ruling in
  creational order (Gen 1-2), not Mosaic concession
- 10:9 synezeuzen: divine passive — God yoked them; the yoke is divine, not merely legal
- 10:12: Mark uniquely includes the woman-divorcing-husband case — writing for Roman audience
  where women had legal right of divorce (vs. Jewish practice where only men could divorce)
- 10:25 kamēlos vs kamilos: "camel" (large animal) is the better-attested reading; "rope"
  or "cable" (kamilos) is a secondary variant attempting to resolve the apparent impossibility
- 10:38 baptisma: "baptism" used metaphorically for immersion in overwhelming suffering
- 10:51 Rabbouni: Aramaic (intensive form of Rabbi = my Master, my Lord)
- 11:9 hōsanna: Aramaic/Hebrew "save now" (Ps 118:25) — originally a petition, used as acclamation
- 11:13 gar ho kairos ouk ēn sykōn: "for it was not the season for figs" — Mark's aside that
  raises the interpretive difficulty of the cursing
- 11:26: absent in best MSS; treated as secondary insertion parallel to Matt 6:15
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK = {
  "10": {
    "1": '<p><strong>Kakeithen anastas erchetai eis ta horia tēs Ioudaias kai peran tou Iordanou</strong> — and rising from there he comes into the region of Judea and across the Jordan — the geographical transition marks the beginning of the Judean ministry and the approach to Jerusalem. <em>peran tou Iordanou</em> (across the Jordan = Perea, Herod Antipas\'s territory east of the Jordan) is included in the regional description. <em>symporeuontai palin ochloi pros auton</em> — crowds come together to him again — <em>palin</em> (again) connects this Judean public ministry to the Galilean teaching-patterns; the crowds follow wherever he goes.</p>',
    "2": '<p><strong>Kai proselthontes Pharisaioi epērōtōn auton ei exestin andri gynaika apolusai peirazōntes auton</strong> — and Pharisees coming to him were asking whether it is lawful for a man to divorce his wife, testing him — <em>peirazō</em> (to test, to tempt — the same word as the Satanic testing in 1:13 and the Pharisaic sign-demand in 8:11). The question is framed as a legal inquiry (<em>ei exestin</em> = is it lawful/permitted) but is explicitly a trap. The Pharisees seek either to discredit Jesus with the crowds (if he opposes the Mosaic permission) or to draw him into a politically dangerous statement (Herod Antipas is in the region and had divorced Herodias\'s husband — John the Baptist was killed for criticizing this arrangement).</p>',
    "3": '<p><strong>Ho de apokritheis eipen autois, Ti hymin eneteilato Mōysēs?</strong> — and answering he said to them: what did Moses command you? — Jesus redirects from the legal question (<em>is it lawful</em>) to the Mosaic command (<em>ti eneteilato</em> = what did he command — the imperative of Torah, not merely its permission). The question distinguishes between what Moses required and what Moses permitted — a distinction the Pharisees will name in v.4.</p>',
    "4": '<p><strong>Hoi de eipan, Epetrepsen Mōysēs biblion apostasiou grapsai kai apolusai</strong> — and they said: Moses permitted to write a certificate of divorce and to divorce — <em>epetrepsen</em> (permitted, allowed — the verb of concession, not command). <em>biblion apostasiou</em> (certificate/book of divorce — the Deuteronomic provision of Deut 24:1) names the mechanism. The Pharisees answer correctly: Moses <em>permitted</em>, not commanded. Jesus will use their own answer against them in v.5.</p>',
    "5": '<p><strong>Ho de Iēsous eipen autois, Pros tēn sklērokardian hymōn egrafen hymin tēn entolēn tautēn</strong> — and Jesus said to them: for your hardness of heart he wrote you this commandment — <em>sklērokardia</em> (hardness of heart — from <em>sklēros</em> = hard/dry + <em>kardia</em> = heart; the theological term for spiritual insensibility, used in Deut 10:16 LXX for the uncircumcised heart). The Mosaic divorce provision is not creation-law but a concession to human moral failure. The concession itself was a mercy — it regulated and limited divorce practice (requiring a formal document, protecting the woman\'s legal status) rather than forbidding it as impossible to enforce against a hard-hearted people.</p>',
    "6": '<p><strong>apo de archēs ktiseōs arsen kai thēly epoiēsen autous</strong> — but from the beginning of creation he made them male and female — <em>apo archēs ktiseōs</em> (from the beginning of creation — the Genesis 1 creation order) is the foundational appeal: Jesus grounds the ruling in the original design of creation rather than the Mosaic concession. The Genesis 1:27 citation establishes sexual differentiation (<em>arsen kai thēly</em> = male and female) as the creational given from which the marriage-unity follows.</p>',
    "7": '<p><strong>heneken toutou kataleisei anthrōpos ton patera autou kai tēn mētera</strong> — for this reason a man will leave his father and mother — the Genesis 2:24 citation: the "leaving" (<em>kataleipō</em> = to leave behind, forsake) of the family of origin is the prior movement that enables the cleaving to the spouse. The priority-inversion from parent-bond to spouse-bond is the creational design, not a cultural custom. In the ANE context, where extended family and patriarchal household dominated social organization, the emphasis on leaving father and mother is a radical statement about the primacy of the marital covenant.</p>',
    "8": '<p><strong>kai esontai hoi dyo eis sarka mian. hōste ouketi eisin dyo alla mia sarx</strong> — and the two will become one flesh. So they are no longer two but one flesh — <em>sarx mia</em> (one flesh) is the Genesis 2:24 description of marital union: a new human entity constituted by the union of two. <em>ouketi eisin dyo</em> (they are no longer two) is Jesus\'s interpretive gloss on the citation: the one-flesh union is not merely a metaphor or a description of sexual union but a statement about a new relational reality. The two-who-were-separate become one-who-was-not-before.</p>',
    "9": '<p><strong>ho oun ho theos synezeuxen, anthrōpos mē chōrizetō</strong> — therefore what God has yoked together, let no human being separate — <em>synezeuxen</em> (yoked together — aorist of <em>syzeugnymi</em> = to yoke together, to pair; the verb for yoking animals for a joint task). The divine passive is emphatic: God is the one who has done the yoking; the marital union is not a human social contract but a divine action. <em>anthrōpos mē chōrizetō</em> (let no human being separate — the prohibitive subjunctive) names the conclusion: since God yokedit, no human authority — legal, social, or personal — has standing to undo it.</p>',
    "10": '<p><strong>Kai eis tēn oikian palin hoi mathētai peri toutou epērōtōn auton</strong> — and in the house again the disciples were asking him about this — the house-setting as private teaching space (cf. 7:17; 9:28; 10:10). The disciples\' private question follows the public controversy; the private teaching (vv.11–12) is the fuller implication of the public ruling.</p>',
    "11": '<p><strong>kai legei autois, Hos an apolusē tēn gynaika autou kai gamēsē allēn moichatai ep\' autēn</strong> — and he says to them: whoever divorces his wife and marries another commits adultery against her — <em>ep\' autēn</em> (against her) is the key syntactical note: the adultery is committed against the divorced wife, not against the new wife or an abstract law. This frames the divorced wife as the party wronged — a significant shift in a legal culture that classified adultery primarily as an offense against a man\'s honor. The divorced wife retains a claim on her husband\'s covenant-fidelity even after the legal dissolution.</p>',
    "12": '<p><strong>kai ean autē apolusasa ton andra autēs gamēsē allon moichatai</strong> — and if she divorces her husband and marries another she commits adultery — Mark uniquely includes the woman-initiating-divorce case, absent from Matthew\'s parallel. In Jewish practice (under Mishnaic law) only the husband could initiate divorce; women did not have the legal right to issue a bill of divorce. Under Roman law, however, women could and did initiate divorce. Mark\'s inclusion of the woman\'s case signals that he is writing for a Roman-context audience for whom the woman\'s case was legally real. The principle is applied symmetrically: the same covenant-logic governs both parties.</p>',
    "13": '<p><strong>Kai prosepheron autō paidia hina autōn hapsētai, hoi de mathētai epetimēsan autois</strong> — and they were bringing little children to him in order that he might touch them; but the disciples rebuked them — <em>paidia</em> (small children — the same word as 9:36–37 where Jesus placed the child in the middle) are brought for touch (<em>hapsētai</em>) — a blessing-touch rather than healing-touch. The disciples\' rebuke (<em>epetimēsan</em> — the word for rebuking demons and the sea) is the gatekeeping impulse applied to the insignificant: children don\'t warrant the teacher\'s time.</p>',
    "14": '<p><strong>idōn de ho Iēsous ēganaktēsen kai eipen autois</strong> — and Jesus seeing it was indignant and said to them — <em>ēganaktēsen</em> (was indignant, was moved with strong displeasure — from <em>aganakteō</em> = to feel moral anger at something wrong). This is the only place in Mark where Jesus is described as indignant at the disciples\' behavior. <strong>Aphete ta paidia erchesthai pros me, mē kōluete auta</strong> — allow the little children to come to me; do not stop them — <em>mē kōluete</em> (do not stop them — the same verb as the unknown exorcist episode in 9:38–39). <strong>tōn gar toioutōn estin hē basileia tou theou</strong> — for of such is the kingdom of God.</p>',
    "15": '<p><strong>amēn legō hymin, hos an mē dexētai tēn basileian tou theou hōs paidion, ou mē eiselthē eis autēn</strong> — truly I tell you: whoever does not receive the kingdom of God as a little child will by no means enter it — the double negative <em>ou mē eiselthē</em> (will by no means enter — the emphatic negation) is absolute. The manner of reception (<em>hōs paidion</em> = as a little child) is the criterion: the child\'s lack of social standing, lack of earned merit, and complete dependence on the giver is the model for kingdom-reception. The child does not negotiate entry or present credentials; the child simply receives what is given. This is the implicit polarity with the rich young man who follows (v.17–22): the child and the rich man represent opposite postures toward the kingdom.</p>',
    "16": '<p><strong>kai enagkalisamenos auta kateulogei titheis tas cheiras ep\' auta</strong> — and taking them in his arms he was blessing them, laying his hands on them — <em>enagkalizomai</em> (to take in the arms, to embrace — used only in 9:36 and here in the NT) is the physical embodiment of the teaching: Jesus embraces the children he has said must be received. <em>kateulogei</em> (was blessing — imperfect, repeated action over multiple children; <em>kata-</em> + <em>eulogeō</em> = to bless intensively). The act embodies the reversal: those the disciples dismissed, Jesus personally embraces and blesses.</p>',
    "17": '<p><strong>kai ekporeuomenou autou eis hodon prosdramōn heis kai gonypetēsas auton epērōta auton</strong> — and as he was going out on the road, running to him one fell on his knees before him and was asking him — <em>prosdramōn</em> (running to him — the urgency of the approach; the same verb as the crowd at 9:15) and <em>gonypetēsas</em> (falling on his knees — the posture of supplication used at 1:40 by the leper) mark the encounter\'s emotional character: this is not a hostile testing but a desperate personal question. <strong>Didaskale agathe, ti poiēsō hina zōēn aiōnion klēronomēsō?</strong> — Good Teacher, what shall I do that I may inherit eternal life? — <em>zōēn aiōnion</em> (eternal life — the Jewish term for the life of the age-to-come) is the question.</p>',
    "19": '<p><strong>tas entolas oidas</strong> — you know the commandments — Jesus lists the six commandments from the Decalogue\'s second table (neighbor-duties): do not murder, do not commit adultery, do not steal, do not bear false witness, do not defraud (<em>mē aposterēsēs</em> — unique to Mark; not in the Decalogue itself; possibly Leviticus 19:13 or Deuteronomy 24:14 against defrauding workers), honor father and mother. <em>mē aposterēsēs</em> (do not defraud/deprive) is inserted where Matthew and Luke have "do not covet" — Mark\'s substitution may reflect the wealthy man\'s specific vulnerability or a textual tradition that applied Decalogue-commandments situationally.</p>',
    "20": '<p><strong>Ho de ephē autō, Didaskale, tauta panta ephylaxamēn ek neotētos mou</strong> — and he said to him: Teacher, all these things I have kept from my youth — <em>ephylaxamēn</em> (I have kept, guarded — aorist of <em>phylassō</em> = to guard, keep watch over; the keeping is comprehensive: all, from childhood to now). The claim is sincere rather than hypocritical: the man genuinely believes he has kept these commandments and is asking what he still lacks. <em>ek neotētos mou</em> (from my youth — from the time of Bar Mitzvah when Torah-obligation began) frames the claim as lifelong observance.</p>',
    "21": '<p><strong>ho de Iēsous emblepsas autō ēgapēsen auton</strong> — and Jesus looking at him loved him — <em>emblepō</em> (to look intently at — the word for direct, penetrating gaze; used for Jesus\'s searching look throughout: 8:25; 10:27; 14:67) is followed immediately by <em>ēgapēsen auton</em> (loved him — the aorist of <em>agapaō</em>, the comprehensive love-word). This is the only place in Mark where Jesus is said to love a specific individual who is not one of the Twelve. The love and the following call are simultaneous. <strong>hen se hysterei</strong> — one thing you lack — <em>hystereō</em> (to fall short, to be lacking — the same root as <em>hysterēma</em>, lack/deficiency). The single gap in comprehensive commandment-keeping is complete, unattached surrender of possessions.</p>',
    "22": '<p><strong>ho de stygnasos epi tō logō apēlthen lypoumenos, ēn gar echōn ktēmata polla</strong> — and he, being gloomy at the word, went away grieving, for he had many possessions — <em>stygnazo</em> (to become gloomy, to have a darkened expression — used in Matt 16:3 for a sky overcast with clouds; the face darkens like an overcast sky). <em>lypoumenos</em> (grieving — present participle: the grief is ongoing as he departs). <em>ktēmata polla</em> (many possessions — property, estates; the word for real property, land, investments) is the reason: not many coins but inherited landed wealth. The man who has kept all the commandments from his youth cannot surrender what he has. Possessions have a prior claim on his identity that the commandments do not.</p>',
    "23": '<p><strong>kai periblepsamenos ho Iēsous legei tois mathētais autou, Pōs dyskolōs hoi ta chrēmata echontes eis tēn basileian tou theou eiseleusontai</strong> — and Jesus looking around says to his disciples: how hard it is for those who have wealth to enter the kingdom of God — <em>periblepsamenos</em> (looking around — the characteristic Markan scanning gaze of Jesus; cf. 3:5,34; 9:8). <em>dyskolōs</em> (with difficulty — the adverb of <em>dyskolos</em> = difficult, hard to manage; literally "disagreeable with food," i.e., finicky; then generally: difficult). The observation is an application of the encounter to a general principle; the disciples\' amazement (v.24) shows it contradicts their assumptions.</p>',
    "24": '<p><strong>hoi de mathētai ethambounto epi tois logois autou, Ho de Iēsous palin apokritheis legei autois, Tekna, pōs dyskolon estin eis tēn basileian tou theou eiselthein</strong> — and the disciples were amazed at his words; and Jesus again answering says to them: children, how hard it is to enter the kingdom of God — <em>ethambounto</em> (were amazed, were dumbfounded — from <em>thambeō</em>; the same verb as 9:15; 10:32; the sense of disoriented surprise). <em>Tekna</em> (Children — the affectionate direct address Jesus uses for the Twelve here only in Mark) softens the rebuke implicit in the repetition. Many manuscripts add "for those who trust in riches" after "enter the kingdom" — an explanatory insertion; the best MSS read the absolute "how hard it is to enter the kingdom of God" without qualification.</p>',
    "25": '<p><strong>eukopoeron estin kamēlon dia [tēs] trymaliās [tēs] rhaphidos dielthein ē plousion eis tēn basileian tou theou eiselthein</strong> — it is easier for a camel to go through the eye of a needle than for a rich person to enter the kingdom of God — <em>kamēlos</em> (camel) is the best-attested reading in all major manuscripts. The variant <em>kamilos</em> (rope, cable — a ship\'s thick rope) appears in some later MSS and in certain patristic citations; it was likely introduced to resolve the apparent impossibility by substituting a very large rope for a very large animal. But the original reading is the camel, and the point is precisely the impossibility: a camel cannot physically pass through the eye of a needle. The saying establishes absolute impossibility — not difficulty but impossibility — which v.27 will then qualify from God\'s side.</p>',
    "26": '<p><strong>hoi de perissōs exeplēssonto legontes pros heautous, Kai tis dynatai sōthēnai?</strong> — and they were exceedingly astonished, saying to one another: and who then can be saved? — <em>perissōs exeplēssonto</em> (exceedingly astonished — the double intensifier: <em>perissōs</em> = exceedingly + <em>ekplēssō</em> = to strike out, astonish thoroughly). The disciples extend the logic: if the rich man who has kept all the commandments cannot enter, who can? Their question is not cynical but genuinely perplexed — they have assumed prosperity as a sign of divine favor (a common assumption in Second Temple Judaism), and Jesus has just inverted that assumption entirely.</p>',
    "27": '<p><strong>emblepsas autois ho Iēsous legei, Para anthrōpois adynaton, all\' ou para theō</strong> — Jesus looking at them says: with humans it is impossible, but not with God — <em>emblepō</em> again (the penetrating gaze). <em>adynaton</em> (impossible — the alpha-privative of <em>dynatos</em> = able; it is not-able). The impossibility is unreservedly affirmed: with humans it is impossible. Then the qualifier: <em>all\' ou para theō</em> (but not with God). <strong>panta gar dynata para tō theō</strong> — for all things are possible with God — this is not the faith-formula of 9:23 (all things possible for the one who believes) but the divine-omnipotence statement: God\'s capacity to save transcends the humanly impossible. The salvation of a rich person is a miracle of divine grace, not human achievement or self-emptying.</p>',
    "28": '<p><strong>Ērxato legein ho Petros autō, Idou hēmeis aphēkamen panta kai ēkolouthēkamen soi</strong> — Peter began to say to him: look, we have left everything and have followed you — <em>aphēkamen panta</em> (we have left everything — the aorist perfect of the disciples\' action contrasted with the rich man\'s inability to leave his possessions). <em>ēkolouthēkamen soi</em> (have followed you — the same perfect of the discipleship-response to the call in 1:18,20). Peter implicitly asks about the reward for those who did what the rich man could not: what do they receive?</p>',
    "29": '<p><strong>ephē ho Iēsous, Amēn legō hymin, oudeis estin hos aphēken oikian ē adelphous ē adelphas ē mētera ē patera ē tekna ē agrous heneken emou kai heneken tou euangeliou</strong> — Jesus said: truly I tell you, no one is who has left house or brothers or sisters or mother or father or children or fields for my sake and for the sake of the gospel — <em>heneken emou kai heneken tou euangeliou</em> (for my sake and for the sake of the gospel) is the double motivation: the person and the message are linked. Mark uniquely adds <em>heneken tou euangeliou</em> alongside <em>heneken emou</em> — the gospel is not separable from allegiance to Jesus; to suffer for the gospel is to suffer for Jesus.</p>',
    "30": '<p><strong>ean mē labē hekatontaplasiona nyn en tō kairō toutō oikias kai adelphous kai adelphas kai mēteras kai tekna kai agrous meta diōgmōn</strong> — if he does not receive a hundredfold now in this present time — houses and brothers and sisters and mothers and children and fields, with persecutions — <em>hekatontaplasiona</em> (a hundredfold) is the multiplication of community: the disciple who left one biological family enters the kingdom-community where many houses, siblings, mothers, and children are available. The list conspicuously omits <em>fathers</em> (<em>pateras</em> absent here though present in v.29\'s list) — possibly because God alone is Father in the new community (cf. Matt 23:9). <em>meta diōgmōn</em> (with persecutions) is the realistic qualifier: the hundredfold comes with suffering, not in its absence. <em>kai en tō aiōni tō erchomenō zōēn aiōnion</em> — and in the coming age, eternal life.</p>',
    "31": '<p><strong>polloi de esontai prōtoi eschatoi kai eschatoi prōtoi</strong> — and many who are first will be last and the last first — the reversal-formula closes the pericope and returns to the theme of 9:35 (greatness = servanthood) and 10:15 (receiving as a child). The rich man who came first (full covenant-observance, wealth as divine favor) will be last; those who left everything (the disciples) occupy a different position in the eschatological ordering. The formula is not about the disciples being complacent (the word <em>many</em> rather than <em>all</em> preserves the warning) but about the total inversion of the expected hierarchy.</p>',
    "32": '<p><strong>Ēsan de en tē hodō anabainontes eis Hierosolyma, kai ēn proagōn autous ho Iēsous, kai ethambounto, hoi de akolouthountes ephobounto</strong> — and they were on the road going up to Jerusalem, and Jesus was going ahead of them, and they were amazed, and those following were afraid — <em>anabainō</em> (to go up — Jerusalem is always <em>up</em> in the Gospels, both geographically and theologically). <em>ēn proagōn autous</em> (was going before them — leading the way) is the ominous image: Jesus walks ahead, the disciples and crowd following in fear and amazement. <em>ethambounto</em> (were amazed) and <em>ephobounto</em> (were afraid) — the double response of awe and terror at the approach to Jerusalem.</p>',
    "33": '<p><strong>hoti idou anabainomen eis Hierosolyma, kai ho huios tou anthrōpou paradothēsetai tois archiereusin kai tois grammateusin, kai katakrinousin auton thanatō kai paradōsousin auton tois ethnesin</strong> — behold we are going up to Jerusalem, and the Son of Man will be delivered to the chief priests and the scribes, and they will condemn him to death and will deliver him to the Gentiles — the third and most detailed passion prediction. <em>paradothēsetai</em> (will be delivered — future passive; the same verb <em>paradidōmi</em> as 9:31 but now future and specifying the recipients: chief priests + scribes = Sanhedrin). <em>katakrinousin auton thanatō</em> (will condemn him to death) is new in this prediction — the formal death sentence is specified. <em>paradōsousin auton tois ethnesin</em> (will deliver him to the Gentiles) — the transfer from Jewish to Roman authority is predicted.</p>',
    "34": '<p><strong>kai empaioxousin autō kai emptysousin autō kai mastigōsousin auton kai apoktanousin, kai meta treis hēmeras anastēsetai</strong> — and they will mock him and spit on him and flog him and kill him; and after three days he will rise — the four actions predicted: <em>empaizō</em> (mock, ridicule), <em>emptyo</em> (spit on — specifically spitting as a gesture of contempt), <em>mastigoō</em> (flog, scourge — the Roman <em>flagellum</em>), <em>apokteinō</em> (kill). The mockery, spitting, and flogging will all occur at the passion: 14:65 (spitting and mockery by the Sanhedrin), 15:17–20 (mockery by soldiers), 15:15 (flogging). The resurrection-prediction closes the prediction as in 8:31 and 9:31.</p>',
    "35": '<p><strong>Kai proserchontai autō Iakōbos kai Iōannēs hoi huioi Zebedaiou legontes autō, Didaskale, thelomen hina ho ean aitēsōmen se poiēsēs hēmin</strong> — and James and John, the sons of Zebedee, came to him saying: Teacher, we want you to do for us whatever we ask you — the request is placed immediately after the third passion prediction — the same structural pattern as Peter\'s post-passion-prediction rebuke (8:32). The disciples consistently fail to integrate what Jesus has just taught about the cross. The open-ended petition (<em>ho ean aitēsōmen</em> = whatever we ask) attempts to lock Jesus into compliance before stating the request.</p>',
    "36": '<p><strong>Ho de eipen autois, Ti thelete me poiēsai hymin?</strong> — and he said to them: what do you want me to do for you? — the same question Jesus will ask Bartimaeus in v.51: <em>ti theleis poiēsō soi?</em> The structural parallel is deliberate: the spiritually blind disciples want thrones; the physically blind Bartimaeus asks for sight. The question exposes the request before Jesus grants or denies it.</p>',
    "37": '<p><strong>Hoi de eipan autō, Dos hēmin hina heis sou ek dexiōn kai heis ex aristeron kathisōmen en tē doxē sou</strong> — and they said: grant us to sit one at your right and one at your left in your glory — <em>ek dexiōn</em> (at the right) and <em>ex aristeron</em> (at the left) are the positions of supreme honor flanking the throne of a king. <em>en tē doxē sou</em> (in your glory) picks up the language of 8:38 (the Son of Man coming in the glory of his Father). James and John have grasped that Jesus will be enthroned in glory but have not grasped that the path to glory runs through the cross of 10:33–34. They ask for the reward without the passion.</p>',
    "38": '<p><strong>Ho de Iēsous eipen autois, Ouk oidate ti aiteisthe. Dynasthe piein to potērion ho egō pinō ē to baptisma ho egō baptizomai baptisthēnai?</strong> — and Jesus said to them: you do not know what you are asking. Are you able to drink the cup that I drink, or to be baptized with the baptism I am being baptized with? — <em>potērion</em> (cup) in the OT is regularly used for God\'s cup of wrath and suffering poured out (Ps 75:8; Isa 51:17; Jer 25:15); cf. Mark 14:36 (Gethsemane: "take this cup from me"). <em>baptisma</em> (baptism) used metaphorically for total immersion in overwhelming suffering: to be immersed in, overwhelmed by, the passion. Both images describe what Jesus is about to undergo — not glory but suffering.</p>',
    "39": '<p><strong>Hoi de eipan autō, Dynastha. Ho de Iēsous eipen autois, To men potērion ho egō pinō piesthe kai to baptisma ho egō baptizomai baptisthēsesthe</strong> — and they said: we are able. And Jesus said to them: the cup I drink you will drink, and the baptism I am being baptized with you will be baptized — the promise is not the thrones they asked for but the suffering they did not ask for. Both James (Acts 12:2 — beheaded by Herod Agrippa, first apostle martyred) and John (tradition: exiled to Patmos; also tradition that he drank from the cup of suffering though not martyred) did experience the baptism of suffering. The promise is not ironic but earnest: the disciples will share the master\'s cup.</p>',
    "40": '<p><strong>to de kathisai ek dexiōn mou ē ex aristeron ouk estin emon dounai, all\' hois hētoimastai</strong> — but to sit at my right or at my left is not mine to give, but for those for whom it has been prepared — <em>ouk estin emon dounai</em> (it is not mine to give) is Jesus\'s limitation-acknowledgment: not every aspect of the eschatological order is within his discretionary authority to grant on request. <em>all\' hois hētoimastai</em> (but for those for whom it has been prepared — divine passive: the Father has prepared these positions) indicates that the seating-arrangement is a matter of divine appointment, not human petition. The positions Jesus does not claim authority to fill are those flanking the throne; the cross, by contrast, is precisely where Mark will place two others (15:27: crucified with a man on his right and one on his left).</p>',
    "41": '<p><strong>Kai akousantes hoi deka ērxanto aganaktein peri Iakōbou kai Iōannou</strong> — and the ten hearing this began to be indignant about James and John — <em>aganakteō</em> (to be indignant, to be morally angry) is the same verb used of Jesus in v.14. The ten\'s indignation is not righteous anger but competitive resentment: James and John had tried to preempt the others. The dispute among the Twelve sets up Jesus\'s teaching on authority-as-service in vv.42–45.</p>',
    "42": '<p><strong>kai proskalesamenos autous ho Iēsous legei autois, Oidate hoti hoi dokountes archein tōn ethnōn katakyreuousin autōn kai hoi megaloi autōn katexousiazousin autōn</strong> — and calling them to himself Jesus says: you know that those who are considered to rule the Gentiles lord it over them and their great ones exercise authority over them — <em>hoi dokountes archein</em> (those who are considered/reputed to rule — <em>dokeō</em> = to seem, to be regarded as; a qualifier that subtly questions whether the authority claimed is genuine). <em>katakyreuō</em> (to lord it over — <em>kata-</em> + <em>kyrios</em> = to exercise lordship downward over, to dominate) and <em>katexousiazō</em> (to exercise authority over, to hold power over) — both <em>kata-</em> compounds indicate downward domination rather than upward service.</p>',
    "43": '<p><strong>ouch houtōs de estin en hymin, all\' hos an thelē megas genesthai en hymin estai hymōn diakonos</strong> — but it is not so among you; but whoever wants to become great among you will be your servant — <em>ouch houtōs de estin en hymin</em> (but it is not so among you) — the kingdom community operates by an inverted principle. <em>diakonos</em> (servant, table-server — the word for waiting on tables; cf. 9:35 where the same term was used in the same teaching context). The grammar is future indicative (<em>estai</em> = will be), not imperative: Jesus is describing the inversion that characterizes genuine kingdom greatness, not merely commanding service.</p>',
    "44": '<p><strong>kai hos an thelē en hymin einai prōtos estai pantōn doulos</strong> — and whoever wants to be first among you will be slave of all — <em>doulos</em> (slave — the stronger word, stronger than <em>diakonos</em>; the slave has no personal rights or time, is wholly at the disposal of the owner). The intensification from v.43: the one who wants to be first (not merely great) must be slave of all (not merely servant). The superlative aspiration requires the most absolute service. This is reinforced by the Son of Man example that follows in v.45.</p>',
    "46": '<p><strong>Kai erchontai eis Ierichō. Kai ekporeuomenou autou apo Ierichō kai tōn mathētōn autou kai ochlou hikanou ho huios Timaiou Bartamaios typhlos prosaitēs ekathēto para tēn hodon</strong> — and they came to Jericho. And as he was leaving Jericho with his disciples and a considerable crowd, Bartimaeus, the son of Timaeus, a blind beggar, was sitting by the road — the full name preservation (<em>Bartamaios ho huios Timaiou</em> = Bartimaeus son of Timaeus — Aramaic <em>bar-Timay</em>) is unusual in Mark\'s healing accounts, which typically leave individuals unnamed (cf. the anonymous leper, hemorrhaging woman, deaf-mute). The named individual was likely known in early Christian communities. <em>typhlos prosaitēs</em> (blind beggar — <em>typhlos</em> = blind; <em>prosaitēs</em> = one who asks for something, a begging person) defines his economic and social situation.</p>',
    "47": '<p><strong>kai akousas hoti Iēsous ho Nazarēnos estin ērxato krazein kai legein, Huie Dauid Iēsou, eleēson me</strong> — and hearing that it was Jesus the Nazarene, he began to cry out and say: Jesus, Son of David, have mercy on me — <em>Iēsou huie Dauid</em> (Jesus, Son of David — the Davidic messianic title) appears here for the first time in Mark addressed to Jesus directly. The crowds at 11:10 will acclaim "the coming kingdom of our father David" in the Triumphal Entry but will not address Jesus as Son of David. Bartimaeus addresses Jesus by the messianic title that carries the healing-king significance: the Davidic king was expected to be a healer (cf. Solomon\'s reputation in Jewish tradition; Ps 72). <em>eleēson me</em> (have mercy on me — the standard petition for divine mercy, <em>eleos</em> = covenant-love expressed as mercy toward the needy).</p>',
    "48": '<p><strong>kai epetimōn autō polloi hina siōpēsē, ho de pollō mallon ekrazen, Huie Dauid, eleēson me</strong> — and many rebuked him to be silent; but he cried out all the more: Son of David, have mercy on me — the crowd\'s rebuke (<em>epetimōn</em> — the same verb as rebuking the children in v.13) and Bartimaeus\'s intensification (<em>pollō mallon ekrazen</em> = cried out much more) mirror the pattern of 7:36 (the more Jesus silenced, the more they proclaimed). Bartimaeus\'s persistence is the faith-in-action that the narrative rewards.</p>',
    "49": '<p><strong>kai stas ho Iēsous eipen, Phōnēsate auton</strong> — and Jesus stopping said: call him — <em>stas</em> (having stopped — aorist participle of <em>histēmi</em>; he halts the journey for this individual). The blind beggar by the road stops the Son of David heading to Jerusalem. The disciples who wanted thrones (v.37) are told to call the blind beggar. <em>Tharsei, egeire, phōnei se</em> — Cheer up! Rise! He is calling you — the three commands addressed to Bartimaeus by the crowd: the crowd that had been silencing him now summons him with urgency.</p>',
    "50": '<p><strong>Ho de apobalōn to himation autou anepēdēsen kai ēlthen pros ton Iēsoun</strong> — and throwing off his cloak he jumped up and came to Jesus — <em>apobalōn to himation</em> (throwing off his cloak) is the vivid physical detail: the outer garment that served as both clothing and bed for a beggar. He abandons it — the one significant possession a beggar has — to come to Jesus. <em>anepēdēsen</em> (jumped up — the only use of this compound verb in the NT; <em>ana-</em> + <em>pēdaō</em> = to leap up) conveys the explosive energy of the response to the summons.</p>',
    "51": '<p><strong>kai apokritheis autō ho Iēsous eipen, Ti soi theleis poiēsō?</strong> — and answering him Jesus said: what do you want me to do for you? — the same question as v.36 to James and John. The structural repetition is interpretive: James and John asked for thrones of glory; Bartimaeus will ask for the most basic restoration. <strong>Ho de typhlos eipen autō, Rabbouni, hina anablepō</strong> — and the blind man said: Rabbouni, that I may see — <em>Rabbouni</em> is the Aramaic intensive form of Rabbi: "my Lord, my great Master" — used elsewhere in the NT only at John 20:16 (Mary Magdalene to the risen Christ). The petition is simple and absolute: <em>hina anablepō</em> (that I might look up, that I might see — <em>anablepō</em> = to look up, to regain/receive sight).</p>',
    "52": '<p><strong>kai Iēsous eipen autō, Hypage, hē pistis sou sesōken se. kai euthys aneblepsen kai ēkolouthei autō en tē hodō</strong> — and Jesus said to him: go, your faith has healed/saved you. And immediately he received sight and was following him on the road — <em>hē pistis sou sesōken se</em> (your faith has saved you — perfect: the saving-effect stands; <em>sōzō</em> = to save/heal, the comprehensive word). <em>euthys</em> again; the healing is instant. The conclusion is the structural climax: <em>ēkolouthei autō en tē hodō</em> (was following him on the road — imperfect: continuous following). The blind beggar who received sight immediately followed Jesus on the road to Jerusalem; he becomes a disciple at the point of healing. The contrast with the rich man (v.22: went away) is complete.</p>'
  },
  "11": {
    "1": '<p><strong>Kai hote engizousin eis Hierosolyma eis Bēthphagē kai Bēthanian pros to oros tōn elaiōn</strong> — and when they drew near to Jerusalem, to Bethphage and Bethany at the Mount of Olives — <em>Bēthphagē</em> (Bethphage = "house of unripe figs" in Aramaic) and <em>Bēthania</em> (Bethany — probably "house of affliction/poverty") are villages on the eastern slope of the Mount of Olives, approximately 2 miles from Jerusalem. <em>pros to oros tōn elaiōn</em> (toward the Mount of Olives) — the approach from the east, the direction of the prophetic return of the divine glory (Ezek 43:1–5; Zech 14:4 where the LORD\'s feet stand on the Mount of Olives at the eschatological coming).</p>',
    "2": '<p><strong>hypagete eis tēn kōmēn tēn katenanti hymōn, kai euthys eisporeuomenoi eis autēn heurēsete pōlon dedemenon eph\' hon oudeis oupō anthrōpōn ekathisen</strong> — go into the village opposite you, and immediately on entering it you will find a colt tied on which no one has ever sat — <em>pōlon</em> (colt — a young animal, specifically a young donkey in the LXX; cf. Zech 9:9 LXX: <em>epibebekōs epi hypozygion kai pōlon neon</em> = riding on a beast of burden and a young colt). The unridden-upon-colt detail (<em>eph\' hon oudeis oupō anthrōpōn ekathisen</em>) parallels requirements for animals used in sacred service (Num 19:2; Deut 21:3: unworked animals for holy purposes). The arrangement anticipates Zechariah 9:9\'s king who comes riding on a colt.</p>',
    "3": '<p><strong>kai ean tis hymin eipē, Ti poieite touto? eipate, Ho kyrios autou chreian echei</strong> — and if anyone says to you: why are you doing this? say: the Lord has need of it — <em>ho kyrios</em> (the Lord) is the title Jesus uses for himself in this instruction — the only place in the Synoptics where Jesus uses <em>kyrios</em> of himself in the third person. The possessive <em>autou chreian echei</em> (has need of it) implies prior ownership or authority: the Lord claims the colt as his own or as available to him. <em>euthys de auton apostellei palin hōde</em> — and he will send it back here immediately — the temporary use with promise of return fits the pattern of commandeering for royal use.</p>',
    "4": '<p><strong>kai apēlthon kai heuron pōlon dedemenon pros thyran exō epi tou amphōdou</strong> — and they went and found a colt tied at a door outside on the street — the detail fulfills the prediction of v.2 precisely: tied, at a doorway, in the street. The precision of the fulfilled instruction is characteristic of the entry\'s presentation as a planned prophetic act rather than an accidental encounter.</p>',
    "5": '<p><strong>kai tines tōn ekei hestēkotōn elegon autois, Ti poieite lyontes ton pōlon?</strong> — and some of those standing there said to them: what are you doing, untying the colt? — the bystanders\' challenge (<em>ti poieite</em> = what are you doing) is exactly the question Jesus anticipated in v.3. The disciples\' response with the Lord\'s word is the test of the arrangement\'s validity.</p>',
    "6": '<p><strong>hoi de eipan autois kathōs eipen ho Iēsous, kai aphēkan autous</strong> — and they said to them as Jesus had told them, and they let them go — the response works: <em>aphēkan autous</em> (they let them go) confirms that the word of the Lord was sufficient authorization. The preparation scene ends with the fulfillment of Jesus\'s prediction at every detail: the colt found, the challenge made, the word given, the release granted.</p>',
    "7": '<p><strong>kai pherosin ton pōlon pros ton Iēsoun kai epiballousin autō ta himatia autōn, kai ekathisen ep\' autō</strong> — and they brought the colt to Jesus and threw their garments on it, and he sat on it — the disciples\' gesture of throwing garments (<em>epiballousin ta himatia autōn</em>) onto the animal is the act of acknowledging royal authority: 2 Kings 9:13 describes the commanders throwing their garments beneath Jehu when he is acclaimed king of Israel. The voluntary garment-casting on the road (v.8) will extend this gesture from a few disciples to the crowd.</p>',
    "8": '<p><strong>kai polloi ta himatia autōn estōsan eis tēn hodon, alloi de stoibadas kopsantes ek tōn agrōn</strong> — and many spread their garments on the road, and others cut branches from the fields — the royal-road-preparation with garments (2 Kgs 9:13) and leafy branches. John 12:13 specifies palm branches (<em>baia tōn phoinikōn</em>); Mark only says <em>stoibadas</em> (leafy branches, rushes — a general word for foliage). Palms were specifically associated with the Feast of Tabernacles and with Maccabean victory celebrations (1 Macc 13:51; 2 Macc 10:7), suggesting the entry activates these eschatological-victory associations.</p>',
    "9": '<p><strong>kai hoi proagontes kai hoi akolouthountes ekrazon, Hōsanna! Eulogēmenos ho erchomenos en onomati kyriou</strong> — and those going before and those following were crying out: Hosanna! Blessed is he who comes in the name of the Lord — <em>Hōsanna</em> is the Greek transliteration of Hebrew <em>hōšaʿ nāʾ</em> (Ps 118:25 LXX: <em>sōson dē</em> = save now!). Originally a petition ("save, please!"), <em>hōsanna</em> had become a liturgical acclamation by the Second Temple period — shouted at Passover pilgrimage as an expression of joy rather than distress. <em>Eulogēmenos ho erchomenos en onomati kyriou</em> is Psalm 118:26 — the pilgrim-greeting for those arriving at the temple. The crowd applies it to Jesus as the specific one who comes in the Lord\'s name.</p>',
    "10": '<p><strong>Eulogēmenē hē erchomenē basileia tou patros hēmōn Dauid</strong> — blessed is the coming kingdom of our father David — the crowd interprets the entry in Davidic-messianic terms: the <em>basileia</em> (kingdom) of David is the expected restoration of the Davidic monarchy. <em>Hōsanna en tois hypsistois</em> (hosanna in the highest — the acclamation directed upward, to the heavenly realm). Mark\'s crowd acclaims the kingdom rather than Jesus directly as son of David (contrast Bartimaeus in 10:47–48 who directly addresses Jesus as Son of David).</p>',
    "11": '<p><strong>kai eisēlthen eis Hierosolyma eis to hieron, kai periblepsamenos panta, opsias ēdē ousēs tēs hōras, exēlthen eis Bēthanian meta tōn dōdeka</strong> — and he entered Jerusalem into the temple, and looking around at everything, since the hour was already late, he went out to Bethany with the Twelve — <em>periblepsamenos panta</em> (looking around at everything — the characteristic Markan scanning gaze; cf. 3:5,34; 5:32; 9:8; 10:23). The survey is strategic: Jesus comes in, looks at everything, makes no immediate dramatic action, and leaves. The anti-climactic departure sets up the temple-action of vv.15–19 as a deliberate return rather than a spontaneous outburst. Mark\'s structure — entry, withdrawal, return with action — underscores the intentionality of the temple-cleansing.</p>',
    "12": '<p><strong>Kai tē epaurion exelthontōn autōn apo Bēthanias epeinase</strong> — and on the following day as they were leaving Bethany, he was hungry — <em>epeinase</em> (was hungry — aorist; genuine physical hunger). The fig tree cursing that follows is framed as arising from genuine hunger, making the symbolic interpretation non-obvious from the story\'s surface level. Mark preserves the detail without explaining it; the interpretation is layered rather than explicit.</p>',
    "13": '<p><strong>kai idōn sykēn apo makrothen echousan phylla ēlthen ei ara ti heurēsei en autē, kai elthōn ep\' autēn ouden heuren ei mē phylla, ho gar kairos ouk ēn sykōn</strong> — and seeing a fig tree from a distance having leaves, he came to see if he would find anything on it, and coming to it he found nothing except leaves, for it was not the season for figs — <em>ho gar kairos ouk ēn sykōn</em> (for it was not the season for figs) is Mark\'s aside that creates the interpretive difficulty: Jesus curses a fig tree for bearing no fruit when it is not fruit-season. In the Mediterranean fig cycle, a tree leafing in spring before Passover should have borne the small early figs (<em>bikkurim</em>, early figs) even before the main crop. A tree in full leaf with no early figs is a tree that shows signs of life but has no fruit — precisely the symbol for the temple establishment that will follow in vv.15–19.</p>',
    "14": '<p><strong>kai apokritheis eipen autē, Mēketi eis ton aiōna ek sou mēdeis karpon phagoitō</strong> — and answering he said to it: may no one eat fruit from you ever again — <em>apokritheis</em> (answering — as if to an implied question; the fig tree\'s full leaves implied a claim to fruitfulness that is now answered). The curse is absolute: <em>mēketi eis ton aiōna</em> (no longer for ever). The optative <em>phagoitō</em> (let eat — the prayer-optative of wish). Mark sandwiches the temple-cleansing between the cursing (v.14) and the withering (v.20–21), a structural technique (the Markan intercalation) that interprets each through the other: the fig tree and the temple are mutually interpretive symbols.</p>',
    "15": '<p><strong>Kai erchontai eis Hierosolyma, kai eiselthōn eis to hieron ērxato ekballein tous pōlountas kai tous agorazontas en tō hierō</strong> — and they came to Jerusalem, and entering the temple he began to drive out those selling and buying in the temple — <em>ekballein</em> (to drive out, to cast out — the same verb as exorcism). The action is against both sellers (<em>tous pōlountas</em>) and buyers (<em>tous agorazontas</em>) — the whole commercial enterprise in the temple courts. The money-changers\' tables and dove-sellers\' benches are overturned. The violence is directed at the commercial apparatus, not at persons.</p>',
    "16": '<p><strong>kai ouk ēphien hina tis denenken skeuos dia tou hierou</strong> — and he would not allow anyone to carry merchandise/a vessel through the temple courts — the prohibition of using the temple as a thoroughfare (<em>diapherein skeuos = carry a vessel/implement through</em>) indicates that the outer courts (the Court of the Gentiles) had become a commercial shortcut as well as a marketplace. This detail, unique to Mark, intensifies the desecration: not merely commerce in the sacred space but using it as a path for ordinary commercial traffic.</p>',
    "18": '<p><strong>Kai ēkousan hoi archiereis kai hoi grammateis kai ezētoun pōs auton apolēsōsin, ephobounto gar auton</strong> — and the chief priests and scribes heard and were seeking how they might destroy him, for they feared him — <em>ezētoun pōs auton apolēsōsin</em> (were seeking how to destroy him — imperfect, ongoing seeking: from this point the execution-plot is in motion). <em>ephobounto gar auton</em> (for they feared him — the reason: not guilt about the temple-arrangements but fear of his popular authority). <em>hoti pas ho ochlos exeplēsseto epi tē didachē autou</em> — for all the crowd was astonished at his teaching — the crowd\'s astonishment (<em>ekplēssō</em>) creates the political constraint: direct arrest risks popular uprising.</p>',
    "19": '<p><strong>Kai hotan opse egeneto, exeporeuonto exō tēs poleōs</strong> — and whenever evening came, they went out of the city — the daily pattern during the Jerusalem week: Jesus and the disciples retire to Bethany each evening (11:11; 11:19; implied 14:3). The withdrawal to Bethany (Mary, Martha, Lazarus\'s village) is the overnight base from which each day\'s Jerusalem-ministry is conducted.</p>',
    "20": '<p><strong>Kai paraporeouomenoi prōi eidon tēn sykēn exērammenen ek rhizōn</strong> — and passing by in the morning they saw the fig tree withered from the roots — <em>exērammenen</em> (withered, dried up — perfect passive participle of <em>xērainō</em>; the same verb as the withered hand of 3:1, the withered-rigid boy of 9:18, and the dried-up spring of 5:29). <em>ek rhizōn</em> (from the roots) emphasizes the totality of the withering: not just the leaves but the root-system. The tree is dead, not merely leafless. The perfect tense indicates a completed state: the withering has occurred and the result stands at the time of discovery.</p>',
    "21": '<p><strong>kai anamnēstheis ho Petros legei autō, Rhabbi, ide hē sykē hēn katērasō exērrantai</strong> — and Peter remembering says to him: Rabbi, look! the fig tree which you cursed has withered — <em>anamnēstheis</em> (having remembered — the same verb as the disciples\' remembering at 14:72 after the denial). Peter connects the withered tree to the curse of the previous day. <em>katērasō</em> (you cursed — aorist; the curse was definitive and its effect is visible). The observation opens the teaching on faith and prayer that follows (vv.22–25).</p>',
    "22": '<p><strong>kai apokritheis ho Iēsous legei autois, Echete pistin theou</strong> — and answering Jesus says to them: have faith of God — <em>pistin theou</em> (faith of God — the genitive is ambiguous: "faith in God" [objective genitive, standard translation] or "God-quality faith" [genitive of quality/source]; the context [mountain-moving, prayer-receiving] supports the former but the genitive of quality is also grammatically possible). The command shifts from the withered fig tree to the principle it illustrates: the power to curse and the power to move mountains both derive from faith-toward-God in prayer.</p>',
    "23": '<p><strong>amēn legō hymin hoti hos an eipē tō orei toutō, Arthēti kai blēthēti eis tēn thalassan, kai mē diakrithē en tē kardia autou alla pisteusē hoti ho lalei ginetai, estai autō</strong> — truly I tell you that whoever says to this mountain: be lifted up and thrown into the sea, and does not doubt in his heart but believes that what he says happens, it will be for him — <em>tō orei toutō</em> (to this mountain — "this mountain" in the Jerusalem context likely refers to the Temple Mount or the Mount of Olives; the metaphor of mountain-moving is a Semitic idiom for doing something extremely difficult or impossible). <em>mē diakrithē en tē kardia autou</em> (does not doubt in his heart — <em>diakrinō</em> = to judge between, to waver between two assessments; the heart divided between trust and doubt). The condition is singleness of faith, not quantity.</p>',
    "24": '<p><strong>dia touto legō hymin, panta hosa proseuchomenoi aiteisthe, pisteuete hoti elabete, kai estai hymin</strong> — therefore I tell you, all things whatever you ask in prayer, believe that you have received them, and they will be for you — <em>pisteuete hoti elabete</em> (believe that you received — aorist, past: the belief treats the answer as already given). The aorist <em>elabete</em> (you received) rather than the present or future is the distinctive grammatical note: the prayer of faith treats the petition as already answered in God\'s purpose, not merely hoped for in the future. This is not a formula for commanding God but the description of how faith engages with divine promise.</p>',
    "25": '<p><strong>kai hotan stēkete proseuchomenoi, aphiete ei ti echete kata tinos, hina kai ho patēr hymōn ho en tois ouranois aphē hymin ta paraptōmata hymōn</strong> — and when you stand praying, forgive if you have anything against anyone, in order that your Father who is in heaven may also forgive you your trespasses — the standing posture for prayer (<em>stēkete proseuchomenoi</em>) is the standard Jewish prayer posture (Luke 18:11; Acts 7:55). The connection of forgiveness-given and forgiveness-received mirrors the Lord\'s Prayer (Matt 6:12,14–15); Mark places it here in connection with efficacious prayer. <em>paraptōmata</em> (trespasses, false steps — from <em>para-</em> + <em>piptō</em> = to fall beside the path, to deviate; the word for moral failure as a deviation from the right course).</p>',
    "26": '<p>Verse 26 — "but if you do not forgive, neither will your Father who is in heaven forgive your trespasses" — is absent from the oldest manuscripts (Sinaiticus, Vaticanus, and others) and is regarded by UBS5/NA28 as a secondary insertion from Matthew 6:15. The verse is a negative formulation of v.25\'s principle; the original Markan text states the positive without the corresponding negative. The interlinear tradition preserves it as a textual reality; most modern critical editions omit it or bracket it.</p>',
    "27": '<p><strong>Kai erchontai palin eis Hierosolyma. kai en tō hierō peripatountos autou erchontai pros auton hoi archiereis kai hoi grammateis kai hoi presbyteroi</strong> — and they came again to Jerusalem, and while he was walking in the temple the chief priests and scribes and elders came to him — the full Sanhedrin delegation: <em>archiereis</em> (chief priests — the temple hierarchy), <em>grammateis</em> (scribes — legal scholars), <em>presbyteroi</em> (elders — lay aristocratic leadership). These are the three groups named in the passion predictions (8:31; 10:33) who will condemn Jesus to death; their approach here is the confrontation that begins the final Jerusalem controversy cycle.</p>',
    "28": '<p><strong>kai elegon autō, En poia exousia tauta poieis? ē tis soi edōken tēn exousian tautēn hina tauta poiēs?</strong> — and they said to him: by what authority are you doing these things? and who gave you this authority to do these things? — <em>poia exousia</em> (what kind of authority — the question about the nature and source of authority). The question is legitimate: prophetic, priestly, and royal authority were the recognized categories; Jesus has acted with the authority of all three without possessing any of their official credentials. The double question (<em>en poia exousia</em> + <em>tis soi edōken</em>) presses both the nature and the source of the authority.</p>',
    "29": '<p><strong>Ho de Iēsous eipen autois, Eperwēsō hymas hena logon, kai apokrithēte moi, kai erō hymin en poia exousia tauta poiō</strong> — and Jesus said to them: I will ask you one question; answer me, and I will tell you by what authority I do these things — the counter-question technique was common in rabbinic controversy: to answer a question with a question, or to make the questioner\'s answer to a prior question determine the answer to the original question. Jesus does not evade the question but sets a precondition for answering it: they must first answer his question.</p>',
    "30": '<p><strong>To baptisma to Iōannou ex ouranou ēn ē ex anthrōpōn? apokrithēte moi</strong> — John\'s baptism — was it from heaven or from humans? Answer me — the question is a dilemma: John\'s baptism was widely regarded by the people as prophetic and authoritative; to deny it a heavenly origin would anger the crowds; to affirm it as heavenly places them in a bind about why they did not accept John\'s testimony to Jesus. <em>ex ouranou</em> (from heaven — the Jewish circumlocution for God; "heaven" used as a substitute for the divine name). The two options are exclusive and exhaustive: either divine or human origin, no middle ground.</p>',
    "31": '<p><strong>kai dielogizonto pros heautous legontes, Ean eipōmen, Ex ouranou, erei, Dia ti [oun] ouk episteusate autō?</strong> — and they deliberated among themselves saying: if we say "from heaven" he will say: why then did you not believe him? — the deliberation (<em>dielogizonto</em> — the internal reasoning-together verb) is exposed to the reader: the leaders debate which answer will cause them less damage. If they say "from heaven," they must explain their rejection of John. The conditional is exact: John\'s preaching included pointing to Jesus (Mark 1:7–8); to affirm John\'s heavenly authority is to implicitly affirm John\'s testimony to Jesus.</p>',
    "32": '<p><strong>alla eipōmen, Ex anthrōpōn — ephobounto ton ochlon, hapantes gar eichon ton Iōannēn hoti ontōs prophētēs ēn</strong> — but if we say "from humans" — they feared the crowd, for all held that John was really a prophet — the second option is equally dangerous: <em>ephobounto ton ochlon</em> (they feared the crowd). <em>hapantes gar eichon ton Iōannēn hoti ontōs prophētēs ēn</em> (for all held John to be truly a prophet) — the universal popular conviction makes "from humans" politically impossible. The leaders are trapped between theological honesty (which would commit them to Jesus) and political safety (which requires them to deny John\'s divine authority).</p>',
    "33": '<p><strong>kai apokrithentes tō Iēsou legousin, Ouk oidamen. Kai ho Iēsous legei autois, Oude egō legō hymin en poia exousia tauta poiō</strong> — and answering Jesus they say: we do not know. And Jesus says to them: neither will I tell you by what authority I do these things — <em>Ouk oidamen</em> (we do not know) is the calculated evasion: they know their answer but will not say it. Jesus\'s response is exact: the precondition he set (answer my question) is unmet; the promised answer (his authority-source) is therefore withheld. The refusal is not punitive but logical: a debate about authority with people who will not honestly address the one prior authority-case is pointless. The question of Jesus\'s authority will be answered definitively at 14:62 — under oath before the Sanhedrin.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'mark')
    merge_comm(existing, MARK)
    save_comm('mkt-original', 'mark', existing)
    ch10 = len(existing.get('10', {}))
    ch11 = len(existing.get('11', {}))
    print(f'Mark 10–11 mkt-original written. Ch 10: {ch10} verses, Ch 11: {ch11} verses.')

if __name__ == '__main__':
    main()
